import React, { useState, useEffect } from "react";
import axios from "axios";

const CustomerDashboard = () => {
  const [job, setJob] = useState({});
  const [jobs, setJobs] = useState([]);

  const handle = (e) =>
    setJob({ ...job, [e.target.name]: e.target.value });

  const post = async () => {
    await axios.post("http://localhost:5000/api/jobs/create", job);
    load();
  };

  const load = async () => {
    const res = await axios.get("http://localhost:5000/api/jobs/all");
    setJobs(res.data);
  };

  useEffect(() => {
    load();
  }, []);

  return (
    <div>

      <h2>Customer Dashboard</h2>

      {/* FORM CARD */}
      <div style={styles.card}>

        <h3>Create Job</h3>

        <input name="title" placeholder="Title" onChange={handle} style={styles.input}/>
        <input name="description" placeholder="Description" onChange={handle} style={styles.input}/>
        <input name="location" placeholder="Location" onChange={handle} style={styles.input}/>
        <input name="price" placeholder="Price" onChange={handle} style={styles.input}/>

        <button style={styles.btn} onClick={post}>Post Job</button>

      </div>

      {/* JOB GRID */}
      <div style={styles.grid}>
        {jobs.map(j => (
          <div key={j._id} style={styles.jobCard}>
            <h4>{j.title}</h4>
            <p>{j.status}</p>
          </div>
        ))}
      </div>

    </div>
  );
};

export default CustomerDashboard;

const styles = {
  card: {
    background: "#111a2e",
    padding: "20px",
    borderRadius: "12px",
    marginBottom: "20px"
  },

  input: {
    width: "100%",
    padding: "10px",
    margin: "5px 0",
    borderRadius: "8px",
    border: "1px solid #1f2a44",
    background: "#0b1220",
    color: "white"
  },

  btn: {
    background: "#22c55e",
    border: "none",
    padding: "10px",
    width: "100%",
    borderRadius: "8px",
    color: "white",
    marginTop: "10px"
  },

  grid: {
    display: "grid",
    gridTemplateColumns: "repeat(auto-fit, minmax(220px, 1fr))",
    gap: "10px"
  },

  jobCard: {
    background: "#111a2e",
    padding: "15px",
    borderRadius: "12px"
  }
};
